import React from 'react';
import DOMPurify from 'dompurify';

function UserBio({ bio }) {
  if (!bio || typeof bio !== 'string') {
    return <div className="user-bio"><p>No bio available.</p></div>;
  }

  const sanitizedBio = DOMPurify.sanitize(bio, {
    ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a', 'p', 'br', 'ul', 'ol', 'li', 'h1', 'h2', 'h3', 'blockquote', 'code', 'pre', 'span'],
    ALLOWED_ATTR: ['href', 'target', 'rel', 'class'],
    ALLOW_DATA_ATTR: false,
  });

  // Force all links to have safe attributes
  const sanitizedWithSafeLinks = sanitizedBio.replace(
    /<a /g,
    '<a rel="noopener noreferrer" target="_blank" '
  );

  return (
    <div
      className="user-bio"
      dangerouslySetInnerHTML={{ __html: sanitizedWithSafeLinks }}
    />
  );
}

export default UserBio;